import csv  # csv module is being imported


class FileAccessManager(object):
    '''
    A class used for managing file access

    Attributes:
        dbFile: string for file containing access information, in CSV format
    '''

    def __init__(self, dbFile='access.csv'):

        self._database = {}  # dictionary used to store database information
        self._loadAccess(dbFile)


    def _loadAccess(self, filename):
         '''
         Takes a filename as an input parameter and loads access info from csv file.
         File format: ID_number, Permission_type

         '''
         with open(filename,'r') as dbfile:

            reader = csv.reader(dbfile,delimiter=',') # CSV reader used to read the database file
            next(reader)  # This skips first row in the database file. 

            for line in reader:
                self._database[line[0]]=line[-1]
        

    def accessAllowed(self, userID):
        '''
        Returns True if a user is allowed permission based on their ID number in the
        access list provided by self._database
        
        Args:
            userID: An integer that's used to check access
        
        Returns: A boolean. True for user allowed; False otherwise

        '''
        return  self._database[str(userID)] == 'yes'


class DocumentManager(object):
    '''
     This class manages documents. The file access control is provided by
     FileAccessManager instance 'fa'. It's used to check if a user has permission
     before opening and reading document files based on their ID number as
     argument of self._getDocumentContents().

    Attributes:
        fa: Instance of the FileAccessManager that has access control information
    '''
    def __init__(self, filename,fa):

        self.fa = fa
        self._fileContents=''  # Content for the document. Initialize it empty 
        self._openDocument(filename)


    def _openDocument(self, filename):
        '''
        Check permission to open file using self.fa.accessAllowed(). It calls
        FileAccessManager's accessAllowed method with argument userID as read from CSV file
        
        Returns a string. Empty if user not allowed; string containing contents of 
        document otherwise

        '''
        return 'Access denied' if  not self.fa.accessAllowed(filename) else 'file opened' 


    def _getDocumentContents(self, filename):
         '''
          Call self._openDocument with argument userID
         '''
         return   self._openDocument(filename)


